const resp  = $input.first().json;
const stats = $('Build AI Prompt').first().json.stats;

let decision = {
  reduce_power:   false,
  reason:         'ไม่สามารถวิเคราะห์ได้',
  recommendation: 'ตรวจสอบด้วยตนเอง',
  risk_level:     'low',
  summary:        '-'
};

try {
  // รองรับทุก format ที่เป็นไปได้
  const rawText =
    resp.choices?.[0]?.message?.content ||  // OpenAI HTTP format
    resp.output ||                           // n8n LangChain / AI Agent
    resp.text   ||                           // n8n LLM Chain
    resp.message?.content ||                 // direct message
    '';

  const match = rawText.match(/\{[\s\S]*\}/);
  if (match) {
    const parsed = JSON.parse(match[0]);
    decision = {
      reduce_power:   parsed.reduce_power === true,
      reason:         parsed.reason         || '-',
      recommendation: parsed.recommendation || '-',
      risk_level:     (parsed.risk_level    || 'low').toLowerCase(),
      summary:        parsed.summary        || '-'
    };
  }
} catch (e) {
  decision.reason = 'Parse error: ' + e.message;
}

const used_model = resp.model || 'openrouter';
const usage      = resp.usage || {};

return [{
  json: {
    ...decision,
    machine_id:       stats.machine_id,
    analyzed_at:      new Date(Date.now() + 7*60*60*1000).toISOString().replace('Z','+07:00'),
    readings_count:   stats.count,
    power_avg_kw:     stats.power_avg_kw,
    power_max_kw:     stats.power_max_kw,
    load_avg_pct:     stats.load_avg_pct,
    load_max_pct:     stats.load_max_pct,
    pf_min:           stats.pf_min,
    alarm_count:      stats.alarm_count,
    spike_count:      stats.spike_count,
    energy_delta_kwh: stats.energy_delta_kwh,
    ai_model:         used_model,
    tokens_used:      usage.total_tokens || 0,
    source:           'n8n-openrouter-5min'
  }
}];

const rows = $input.all();
const now = new Date();
const oneMinAgo = new Date(now.getTime() - 1 * 60 * 1000);

// กรองเฉพาะ 1 นาทีล่าสุดก่อน
let recent = rows.filter(r => {
  const ts = new Date(r.json.timestamp);
  return !isNaN(ts.getTime()) && ts >= oneMinAgo;
});

// fallback: ถ้าไม่มีข้อมูลใน 1 นาที ใช้ 12 rows ล่าสุด (~1 นาที ที่ 5s/row)
const usedFallback = recent.length === 0;
if (usedFallback) {
  recent = rows.slice(-12);
}

if (recent.length === 0) {
  return [{ json: { skip: true, reason: 'ไม่มีข้อมูลในระบบเลย', count: 0 } }];
}

const num  = v => parseFloat(v) || 0;
const avg  = arr => arr.reduce((a,b) => a+b, 0) / arr.length;
const max  = arr => Math.max(...arr);
const min  = arr => Math.min(...arr);

const powers   = recent.map(r => num(r.json.active_power_kw));
const reactive = recent.map(r => num(r.json.reactive_power_kvar));
const apparent = recent.map(r => num(r.json.apparent_power_kva));
const pfs      = recent.map(r => num(r.json.power_factor));
const loads    = recent.map(r => num(r.json.load_pct));
const currents = recent.map(r => num(r.json.current_max));
const rpms     = recent.map(r => num(r.json.motor_rpm));
const freqs    = recent.map(r => num(r.json.frequency_hz));

const alarmCount = recent.filter(r =>
  r.json.alarm_overcurrent === true ||
  r.json.alarm_overcurrent === 'true' ||
  r.json.alarm_overcurrent === 'TRUE'
).length;
const spikeCount = recent.filter(r =>
  r.json.spike_event === true ||
  r.json.spike_event === 'true' ||
  r.json.spike_event === 'TRUE'
).length;

const energyFirst = num(recent[0].json.energy_today_kwh);
const energyLast  = num(recent[recent.length-1].json.energy_today_kwh);
const energyDelta = Number(Math.max(0, energyLast - energyFirst).toFixed(4));

return [{
  json: {
    skip:              false,
    used_fallback:     usedFallback,
    machine_id:        recent[0].json.machine_id || 'MC-01',
    count:             recent.length,
    time_from:         recent[0].json.timestamp,
    time_to:           recent[recent.length-1].json.timestamp,

    power_avg_kw:      Number(avg(powers).toFixed(3)),
    power_max_kw:      Number(max(powers).toFixed(3)),
    power_min_kw:      Number(min(powers).toFixed(3)),

    reactive_avg_kvar: Number(avg(reactive).toFixed(3)),
    apparent_avg_kva:  Number(avg(apparent).toFixed(3)),

    pf_avg:            Number(avg(pfs).toFixed(3)),
    pf_min:            Number(min(pfs).toFixed(3)),

    load_avg_pct:      Number(avg(loads).toFixed(1)),
    load_max_pct:      Number(max(loads).toFixed(1)),

    current_avg_a:     Number(avg(currents).toFixed(2)),
    current_max_a:     Number(max(currents).toFixed(2)),

    rpm_avg:           Math.round(avg(rpms)),
    freq_avg_hz:       Number(avg(freqs).toFixed(2)),

    energy_delta_kwh:  energyDelta,
    alarm_count:       alarmCount,
    spike_count:       spikeCount,
    alarm_rate_pct:    Number((alarmCount / recent.length * 100).toFixed(1)),
    spike_rate_pct:    Number((spikeCount  / recent.length * 100).toFixed(1))
  }
}];
